output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?duration WHERE {
  ?series wdt:P31 wd:Q3392064 ; wdt:P1319 ?year ; wdt:P1676 wd:Q334634 ; wdt:P1676 wd:Q650840 .
  VALUES ?year {
    "1977" "1978" "2008" "2009"
  }
  ?series wdt:P1545 ?game .
  ?game wdt:P1068 ?duration .
}
ORDER BY ASC(?duration)
OFFSET 4
LIMIT 1

